import * as React from 'react';
import Login from './pages/Login'
import StudentDashboard from './pages/StudentDashboard'
import TeacherDashboard from './pages/TeacherDashboard'
import StudentFeed from './pages/StudentFeed'
import TeacherFeed from './pages/TeacherFeed';
import { ThemeProvider, createTheme } from '@material-ui/core/styles';
import { BrowserRouter, Route, Routes } from 'react-router-dom';
import Layout from './components/Layout';
import Quiz from './pages/Quiz';
import VideoStream from './components/VideoStream';
import Register from './pages/Register';
import CreateClassroom from './pages/CreateClassroom';
import Admin from './pages/Admin';
import AdminLayout from './components/AdminLayout';
import CreateAdmin from './pages/CreateAdmin';

const theme = createTheme({
  typography: {
    fontFamily: 'Quicksand'
  },
  palette: {
    primary: {
      main: "#111"
    },
    secondary: {
      main: '#162276'
    },
    error: {
      main: '#ffffff'
    }
  }
});


function App() {
  return (
    <ThemeProvider theme={theme}>
      <BrowserRouter>
        <Routes>

            <Route path='/' element={<Login />} />

            <Route path='/register' element={<Register />} />

            <Route path='/studentDashboard' element={<Layout><StudentDashboard /></Layout>} />

            <Route path='/teacherDashboard' element={<Layout><TeacherDashboard /></Layout>} />

            <Route path='/studentFeed' element={<Layout><StudentFeed /></Layout>} />

            <Route path='/teacherFeed' element={<Layout><TeacherFeed /></Layout>} />

            <Route path='/createClassroom' element={<Layout><CreateClassroom /></Layout>} />

            <Route path='/quiz' element={<Quiz />} />

            <Route path='/videoStream' element={<VideoStream />} />

            <Route path='/admin' element={<AdminLayout><Admin /></AdminLayout>} />


            <Route path='/admin' element={<AdminLayout><CreateAdmin /></AdminLayout>} />

        </Routes>
      </BrowserRouter>
    </ThemeProvider>
  );
}

export default App;
